
CREATE   PROCEDURE METRAPQ.usp_Merge_QuoteRichieste
AS
BEGIN
    SET NOCOUNT ON;

    MERGE INTO METRAPQ.QuoteRichieste AS TGT
    USING METRAPQ.QuoteRichiesteView AS SRC ON (
         SRC.NumeroProgressivo = TGT.NumeroProgressivo 
    )

    WHEN MATCHED AND SRC.ChangeHashKey <> TGT.ChangeHashKey
      THEN UPDATE SET TGT.ChangeHashKey = SRC.ChangeHashKey, TGT.UpdateDatetime = SRC.UpdateDatetime, TGT.IsDeleted = SRC.IsDeleted, 
        TGT.CodiceMetra = SRC.CodiceMetra, TGT.Revisione = SRC.Revisione, TGT.UltimaModifica = SRC.UltimaModifica, TGT.DataModificaArchivio = SRC.DataModificaArchivio, TGT.IDClassificazioneProdotto = SRC.IDClassificazioneProdotto, TGT.Ascona = SRC.Ascona, TGT.Strappo = SRC.Strappo, TGT.Dima = SRC.Dima, TGT.numeroCassetto = SRC.numeroCassetto, TGT.CertificatiRichiesti = SRC.CertificatiRichiesti, TGT.particolareDiSicurezza = SRC.particolareDiSicurezza, TGT.prodottoStandard = SRC.prodottoStandard, TGT.rullatura = SRC.rullatura, TGT.ControlloUltrasuoni = SRC.ControlloUltrasuoni, TGT.marcareBarre = SRC.marcareBarre, TGT.AssegnareLotto = SRC.AssegnareLotto, TGT.NoteRGQ = SRC.NoteRGQ, TGT.SegnalazioniContestazioni = SRC.SegnalazioniContestazioni, TGT.ScorrimentoT = SRC.ScorrimentoT, TGT.NormaTolleranze = SRC.NormaTolleranze, TGT.LegaPredefinita = SRC.LegaPredefinita, TGT.LegaPredefinita_IDClassificazioneCaratteristiche = SRC.LegaPredefinita_IDClassificazioneCaratteristiche, TGT.StatoFisicoPredefinito = SRC.StatoFisicoPredefinito, TGT.StatoFisicoPredefinito_IDClassificazioneCaratteristiche = SRC.StatoFisicoPredefinito_IDClassificazioneCaratteristiche, TGT.DurezzaMaxRichiesta = SRC.DurezzaMaxRichiesta, TGT.DurezzaMaxRichiesta_IDClassificazioneCaratteristiche = SRC.DurezzaMaxRichiesta_IDClassificazioneCaratteristiche, TGT.DurezzaMinRichiesta = SRC.DurezzaMinRichiesta, TGT.DurezzaMinRichiesta_IDClassificazioneCaratteristiche = SRC.DurezzaMinRichiesta_IDClassificazioneCaratteristiche, TGT.RMRichiesto = SRC.RMRichiesto, TGT.RmRichiesto_IDClassificazioneCaratteristiche = SRC.RmRichiesto_IDClassificazioneCaratteristiche, TGT.RPRichiesto = SRC.RPRichiesto, TGT.RpRichiesto_IDClassificazioneCaratteristiche = SRC.RpRichiesto_IDClassificazioneCaratteristiche, TGT.ARichiesto = SRC.ARichiesto, TGT.ARichiesto_IDClassificazioneCaratteristiche = SRC.ARichiesto_IDClassificazioneCaratteristiche, TGT.ARichiestoTipo = SRC.ARichiestoTipo, TGT.RARichiesto = SRC.RARichiesto, TGT.RaRichiesto_IDClassificazioneCaratteristiche = SRC.RaRichiesto_IDClassificazioneCaratteristiche, TGT.RTRichiesto = SRC.RTRichiesto, TGT.RtRichiesto_IDClassificazioneCaratteristiche = SRC.RtRichiesto_IDClassificazioneCaratteristiche, TGT.RZRichiesto = SRC.RZRichiesto, TGT.RzRichiesto_IDClassificazioneCaratteristiche = SRC.RzRichiesto_IDClassificazioneCaratteristiche, TGT.RMaxRichiesto = SRC.RMaxRichiesto, TGT.RmaxRichiesto_IDClassificazioneCaratteristiche = SRC.RmaxRichiesto_IDClassificazioneCaratteristiche, TGT.NormaCaratteristicheMeccaniche = SRC.NormaCaratteristicheMeccaniche, TGT.NormaProveDurezza = SRC.NormaProveDurezza, TGT.NormaProveDiTrazione = SRC.NormaProveDiTrazione, TGT.NormaRugosita = SRC.NormaRugosita, TGT.TolleranzaCommercialeDelPesoSup = SRC.TolleranzaCommercialeDelPesoSup, TGT.TolleranzaCommercialeDelPesoInf = SRC.TolleranzaCommercialeDelPesoInf, TGT.Sistema = SRC.Sistema, TGT.SistemaID = SRC.SistemaID, TGT.Serie = SRC.Serie, TGT.SerieID = SRC.SerieID, TGT.Commessa = SRC.Commessa, TGT.NumeroCommessa = SRC.NumeroCommessa, TGT.NormaProprietaMeccaniche = SRC.NormaProprietaMeccaniche, TGT.OpportunitaNumero = SRC.OpportunitaNumero, TGT.OpportunitaDescrizione = SRC.OpportunitaDescrizione, TGT.OpportunitaIDSaleforce = SRC.OpportunitaIDSaleforce, TGT.TipoDurezza = SRC.TipoDurezza

    WHEN NOT MATCHED BY TARGET
      THEN INSERT (NumeroProgressivo, HistoricalHashKey, ChangeHashKey, InsertDatetime, UpdateDatetime, IsDeleted, CodiceMetra, Revisione, UltimaModifica, DataModificaArchivio, IDClassificazioneProdotto, Ascona, Strappo, Dima, numeroCassetto, CertificatiRichiesti, particolareDiSicurezza, prodottoStandard, rullatura, ControlloUltrasuoni, marcareBarre, AssegnareLotto, NoteRGQ, SegnalazioniContestazioni, ScorrimentoT, NormaTolleranze, LegaPredefinita, LegaPredefinita_IDClassificazioneCaratteristiche, StatoFisicoPredefinito, StatoFisicoPredefinito_IDClassificazioneCaratteristiche, DurezzaMaxRichiesta, DurezzaMaxRichiesta_IDClassificazioneCaratteristiche, DurezzaMinRichiesta, DurezzaMinRichiesta_IDClassificazioneCaratteristiche, RMRichiesto, RmRichiesto_IDClassificazioneCaratteristiche, RPRichiesto, RpRichiesto_IDClassificazioneCaratteristiche, ARichiesto, ARichiesto_IDClassificazioneCaratteristiche, ARichiestoTipo, RARichiesto, RaRichiesto_IDClassificazioneCaratteristiche, RTRichiesto, RtRichiesto_IDClassificazioneCaratteristiche, RZRichiesto, RzRichiesto_IDClassificazioneCaratteristiche, RMaxRichiesto, RmaxRichiesto_IDClassificazioneCaratteristiche, NormaCaratteristicheMeccaniche, NormaProveDurezza, NormaProveDiTrazione, NormaRugosita, TolleranzaCommercialeDelPesoSup, TolleranzaCommercialeDelPesoInf, Sistema, SistemaID, Serie, SerieID, Commessa, NumeroCommessa, NormaProprietaMeccaniche, OpportunitaNumero, OpportunitaDescrizione, OpportunitaIDSaleforce, TipoDurezza)
        VALUES (NumeroProgressivo, HistoricalHashKey, ChangeHashKey, InsertDatetime, UpdateDatetime, IsDeleted, CodiceMetra, Revisione, UltimaModifica, DataModificaArchivio, IDClassificazioneProdotto, Ascona, Strappo, Dima, numeroCassetto, CertificatiRichiesti, particolareDiSicurezza, prodottoStandard, rullatura, ControlloUltrasuoni, marcareBarre, AssegnareLotto, NoteRGQ, SegnalazioniContestazioni, ScorrimentoT, NormaTolleranze, LegaPredefinita, LegaPredefinita_IDClassificazioneCaratteristiche, StatoFisicoPredefinito, StatoFisicoPredefinito_IDClassificazioneCaratteristiche, DurezzaMaxRichiesta, DurezzaMaxRichiesta_IDClassificazioneCaratteristiche, DurezzaMinRichiesta, DurezzaMinRichiesta_IDClassificazioneCaratteristiche, RMRichiesto, RmRichiesto_IDClassificazioneCaratteristiche, RPRichiesto, RpRichiesto_IDClassificazioneCaratteristiche, ARichiesto, ARichiesto_IDClassificazioneCaratteristiche, ARichiestoTipo, RARichiesto, RaRichiesto_IDClassificazioneCaratteristiche, RTRichiesto, RtRichiesto_IDClassificazioneCaratteristiche, RZRichiesto, RzRichiesto_IDClassificazioneCaratteristiche, RMaxRichiesto, RmaxRichiesto_IDClassificazioneCaratteristiche, NormaCaratteristicheMeccaniche, NormaProveDurezza, NormaProveDiTrazione, NormaRugosita, TolleranzaCommercialeDelPesoSup, TolleranzaCommercialeDelPesoInf, Sistema, SistemaID, Serie, SerieID, Commessa, NumeroCommessa, NormaProprietaMeccaniche, OpportunitaNumero, OpportunitaDescrizione, OpportunitaIDSaleforce, TipoDurezza)

    WHEN NOT MATCHED BY SOURCE AND TGT.IsDeleted = CAST(0 AS BIT)
      THEN UPDATE SET TGT.ChangeHashKey = CONVERT(VARBINARY(32), 0),
        TGT.UpdateDatetime = CURRENT_TIMESTAMP,
        TGT.IsDeleted = CAST(1 AS BIT)
    
    OUTPUT
        CURRENT_TIMESTAMP AS merge_datetime,
        CASE WHEN Inserted.IsDeleted = CAST(1 AS BIT) THEN N'DELETE' ELSE $action END AS merge_action,
        'METRAPQ.QuoteRichieste' AS full_olap_table_name,
         'NumeroProgressivo = ' + CAST(COALESCE(inserted.NumeroProgressivo, deleted.NumeroProgressivo) AS NVARCHAR) AS primary_key_description
    INTO audit.merge_log_details;

END
GO

